#include <OneWire.h>
#include <DallasTemperature.h>
#include <SD.h>
#define LVDT_PIN A0
#define RELAY_PIN 7
#define BUZZER 8
#define LED 9
#define SD_CS 10
#define ONE_WIRE_BUS 2
#define SPAN_M 20.0f
#define ALPHA 12e-6f
#define DEV_LIMIT 3.0f
#define LVDT_SCALE 20.0f
#define LVDT_OFFSET 10.0f
OneWire ow(ONE_WIRE_BUS); DallasTemperature ds(&ow);
float T_ref=20.0f, gap_ref=15.0f;
float intg=0,lastE=0,lastGap=0;

float thermal_expansion_gap(float a,float L,float dT){return a*L*dT*1000.0f;}

float read_gap_mm(){return (analogRead(LVDT_PIN)/1023.0f)*LVDT_SCALE-LVDT_OFFSET;}

float read_temp(){
  ds.requestTemperatures();
  return (ds.getTempCByIndex(0)+ds.getTempCByIndex(1))/2.0f;
}

void check_anomaly(float gap,float T){
  float dT=T-T_ref;
  float pred=gap_ref+thermal_expansion_gap(ALPHA,SPAN_M,dT);
  float dev=fabs(gap-pred);
  float rate=(gap-lastGap)/3600.0f;
  float expected_rate=thermal_expansion_gap(ALPHA,SPAN_M,0.5f)/3600.0f;
  if(dev>DEV_LIMIT||fabs(rate)>expected_rate*2.5f){
    tone(BUZZER,1500);analogWrite(LED,255);
    digitalWrite(RELAY_PIN,HIGH);delay(200);digitalWrite(RELAY_PIN,LOW);
  }else{noTone(BUZZER);analogWrite(LED,(int)(dev/DEV_LIMIT*100));}
  lastGap=gap;
}

void log_sd(float gap,float T){
  File f=SD.open("joint.csv",FILE_WRITE);
  float pred=gap_ref+thermal_expansion_gap(ALPHA,SPAN_M,T-T_ref);
  if(f){f.print(millis());f.print(',');f.print(T);f.print(',');f.print(gap);f.print(',');f.println(pred);f.close();}
}

void setup(){Serial.begin(115200);ds.begin();SD.begin(SD_CS);pinMode(RELAY_PIN,OUTPUT);pinMode(BUZZER,OUTPUT);pinMode(LED,OUTPUT);}

void loop(){float gap=read_gap_mm();float T=read_temp();check_anomaly(gap,T);log_sd(gap,T);Serial.print("gap=");Serial.print(gap);Serial.print(" T=");Serial.println(T);delay(3600000);}
